// ═══════════════════════════════════════════════════════════════════════════════
// Deep cross-validation of NSGA-II non-dominated sorting against Python Optuna.
//
// Baseline: tests/nsga_deep_baseline.json (generated by generate_nsga_deep_baseline.py)
// Covers:
//  1. dominates() — all direction combos, inf, equal, trade-off
//  2. fast_non_dominated_sort() — rank assignment with duplicates, 3+ fronts, 
//     single obj, mixed direction, NaN objectives
//  3. crowding_distance() — Python-exact normalization, inf padding, sort order
//  4. is_pareto_front() — front membership
//  5. Large 10-trial 3-obj problem — full pipeline
// ═══════════════════════════════════════════════════════════════════════════════

use std::collections::HashMap;
use optuna_rs::multi_objective::{
    crowding_distance, dominates, fast_non_dominated_sort, is_pareto_front,
};
use optuna_rs::study::StudyDirection;
use optuna_rs::trial::{FrozenTrial, TrialState};

const TOL: f64 = 1e-9;

fn load() -> serde_json::Value {
    let data = include_str!("nsga_deep_baseline.json");
    serde_json::from_str(data).expect("parse nsga_deep_baseline.json")
}

fn jf64(v: &serde_json::Value) -> f64 {
    match v {
        serde_json::Value::Number(n) => n.as_f64().unwrap(),
        serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
        serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
        serde_json::Value::String(s) if s == "NaN" => f64::NAN,
        _ => panic!("unexpected json value: {v:?}"),
    }
}

fn jf64_vec(arr: &serde_json::Value) -> Vec<f64> {
    arr.as_array().unwrap().iter().map(jf64).collect()
}

fn ji64_vec(arr: &serde_json::Value) -> Vec<i64> {
    arr.as_array().unwrap().iter().map(|v| v.as_i64().unwrap()).collect()
}

fn assert_close(got: f64, exp: f64, tol: f64, label: &str) {
    if exp.is_infinite() {
        assert!(
            got.is_infinite() && got.signum() == exp.signum(),
            "{label}: expected {exp}, got {got}"
        );
    } else if exp.is_nan() {
        assert!(got.is_nan(), "{label}: expected NaN, got {got}");
    } else {
        let diff = (got - exp).abs();
        let denom = exp.abs().max(1.0);
        assert!(
            diff / denom < tol,
            "{label}: expected {exp}, got {got}, rel_err={:.2e}",
            diff / denom
        );
    }
}

fn make_trial(number: i64, values: Vec<f64>) -> FrozenTrial {
    FrozenTrial::new(
        number,
        TrialState::Complete,
        None,
        Some(values),
        Some(chrono::Utc::now()),
        Some(chrono::Utc::now()),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        number,
    )
    .unwrap()
}

/// Convert fronts (Vec<Vec<usize>>) to per-trial rank array
fn fronts_to_ranks(fronts: &[Vec<usize>], n: usize) -> Vec<i64> {
    let mut ranks = vec![-1i64; n];
    for (rank, front) in fronts.iter().enumerate() {
        for &idx in front {
            ranks[idx] = rank as i64;
        }
    }
    ranks
}

// ═══════════════════════════════════════════════════════════════════════════
//  1. dominates() — 1D cases from Python test_dominates_1d_not_equal
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn deep_cv_dominates_1d_not_equal() {
    let b = load();
    let cases = b["dom_1d_not_equal"].as_array().unwrap();
    for (i, case) in cases.iter().enumerate() {
        let v1 = jf64(&case["v1"]);
        let v2 = jf64(&case["v2"]);
        let py_dom_min = case["dom_min"].as_bool().unwrap();
        let py_dom_max = case["dom_max"].as_bool().unwrap();

        let rs_dom_min = dominates(&[v1], &[v2], &[StudyDirection::Minimize]);
        let rs_dom_max = dominates(&[v1], &[v2], &[StudyDirection::Maximize]);

        assert_eq!(
            rs_dom_min, py_dom_min,
            "dom_1d_not_equal[{i}] minimize: v1={v1}, v2={v2}"
        );
        assert_eq!(
            rs_dom_max, py_dom_max,
            "dom_1d_not_equal[{i}] maximize: v1={v1}, v2={v2}"
        );
    }
}

#[test]
fn deep_cv_dominates_1d_equal() {
    let b = load();
    let cases = b["dom_1d_equal"].as_array().unwrap();
    for (i, case) in cases.iter().enumerate() {
        let v = jf64(&case["v"]);
        let py_dom_min = case["dom_min"].as_bool().unwrap();
        let py_dom_max = case["dom_max"].as_bool().unwrap();

        // Equal values: never dominates (irreflexive)
        let rs_dom_min = dominates(&[v], &[v], &[StudyDirection::Minimize]);
        let rs_dom_max = dominates(&[v], &[v], &[StudyDirection::Maximize]);

        assert_eq!(rs_dom_min, py_dom_min, "dom_1d_equal[{i}] minimize: v={v}");
        assert_eq!(rs_dom_max, py_dom_max, "dom_1d_equal[{i}] maximize: v={v}");
    }
}

// ═══════════════════════════════════════════════════════════════════════════
//  1b. dominates() — mixed direction 2D
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn deep_cv_dominates_mixed_direction() {
    // Minimize obj0, Maximize obj1
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Maximize];

    // a=[1,3], b=[2,2]: a better in both (lower-min, higher-max) → dominates
    assert!(dominates(&[1.0, 3.0], &[2.0, 2.0], &dirs));
    // reverse: b does NOT dominate a
    assert!(!dominates(&[2.0, 2.0], &[1.0, 3.0], &dirs));
    // trade-off: a=[1,2], b=[2,3]: a better in obj0(min), b better in obj1(max) → neither
    assert!(!dominates(&[1.0, 2.0], &[2.0, 3.0], &dirs));
    assert!(!dominates(&[2.0, 3.0], &[1.0, 2.0], &dirs));
    // equal in one, better in other: a=[1,3], b=[1,2] → a dominates (same min, better max)
    assert!(dominates(&[1.0, 3.0], &[1.0, 2.0], &dirs));
    assert!(!dominates(&[1.0, 2.0], &[1.0, 3.0], &dirs));
}

#[test]
fn deep_cv_dominates_inf_values() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    // -inf dominates finite
    assert!(dominates(&[f64::NEG_INFINITY, 1.0], &[0.0, 1.0], &dirs));
    // finite dominates inf
    assert!(dominates(&[0.0, 1.0], &[f64::INFINITY, 1.0], &dirs));
    // -inf vs inf
    assert!(dominates(
        &[f64::NEG_INFINITY],
        &[f64::INFINITY],
        &[StudyDirection::Minimize]
    ));
    // inf vs -inf for maximize
    assert!(dominates(
        &[f64::INFINITY],
        &[f64::NEG_INFINITY],
        &[StudyDirection::Maximize]
    ));
}

