/// Test all parametrized cases from Python test_fast_non_domination_rank
#[test]
fn deep_cv_fns_rank_cases() {
    let b = load();
    let cases = b["fns_rank_cases"].as_array().unwrap();
    let dirs_min2 = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let dirs_min3 = vec![
        StudyDirection::Minimize,
        StudyDirection::Minimize,
        StudyDirection::Minimize,
    ];

    for (ci, case) in cases.iter().enumerate() {
        let values: Vec<Vec<f64>> = case["values"]
            .as_array()
            .unwrap()
            .iter()
            .map(|row| row.as_array().unwrap().iter().map(|v| v.as_f64().unwrap()).collect())
            .collect();
        let expected_ranks = ji64_vec(&case["expected_ranks"]);
        let n_obj = values[0].len();
        let dirs = if n_obj == 2 { &dirs_min2 } else { &dirs_min3 };

        let trials: Vec<FrozenTrial> = values
            .iter()
            .enumerate()
            .map(|(i, v)| make_trial(i as i64, v.clone()))
            .collect();
        let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
        let fronts = fast_non_dominated_sort(&trial_refs, dirs);
        let ranks = fronts_to_ranks(&fronts, trials.len());

        assert_eq!(
            ranks, expected_ranks,
            "fns_rank_cases[{ci}] values={values:?}"
        );
    }
}

