/// Verify duplicate handling: identical solutions should share rank=0
#[test]
fn deep_cv_fns_duplicates() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    // 3 identical solutions → all on front 0 (none dominates another)
    let trials: Vec<FrozenTrial> = (0..3)
        .map(|i| make_trial(i as i64, vec![1.0, 1.0]))
        .collect();
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let fronts = fast_non_dominated_sort(&trial_refs, &dirs);
    let ranks = fronts_to_ranks(&fronts, 3);
    assert_eq!(ranks, vec![0, 0, 0], "all duplicates should be rank 0");
}

/// Python test case: 7 trials with duplicates (2D)
