// ═══════════════════════════════════════════════════════════════════════════
//  3. crowding_distance — Python-exact values
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn deep_cv_cd_1d_cases() {
    let b = load();
    let cases = b["cd_python_exact"].as_array().unwrap();

    for (ci, case) in cases.iter().enumerate() {
        let values: Vec<Vec<f64>> = case["values"]
            .as_array()
            .unwrap()
            .iter()
            .map(|row| {
                row.as_array()
                    .unwrap()
                    .iter()
                    .map(jf64)
                    .collect()
            })
            .collect();
        let expected_dists = jf64_vec(&case["distances"]);

        let trials: Vec<FrozenTrial> = values
            .iter()
            .enumerate()
            .map(|(i, v)| make_trial(i as i64, v.clone()))
            .collect();
        let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
        let dirs: Vec<StudyDirection> = vec![StudyDirection::Minimize; values[0].len()];
        let cd = crowding_distance(&trial_refs, &dirs);

        assert_eq!(
            cd.len(),
            expected_dists.len(),
            "cd_python_exact[{ci}] length mismatch"
        );

        // Crowding distance doesn't depend on direction (it's per-index, not trial.number)
        // But Python uses trial.number as key. Since we create trials with number=index,
        // the mapping should align.
        // However, crowding_distance in Rust returns distances in trial_refs order,
        // while Python sorts by each objective. The final sum should be the same.
        for (j, (&got, &exp)) in cd.iter().zip(expected_dists.iter()).enumerate() {
            assert_close(got, exp, TOL, &format!("cd_python_exact[{ci}][{j}]"));
        }
    }
}

