// ═══════════════════════════════════════════════════════════════════════════
//  3b. crowding_distance sort order — matches Python _crowding_distance_sort
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn deep_cv_cd_sort_order() {
    let b = load();
    let cases = b["cd_sort_order"].as_array().unwrap();

    for (ci, case) in cases.iter().enumerate() {
        let values: Vec<Vec<f64>> = case["values"]
            .as_array()
            .unwrap()
            .iter()
            .map(|row| row.as_array().unwrap().iter().map(jf64).collect())
            .collect();
        let expected_dists = jf64_vec(&case["distances"]);
        let expected_sorted: Vec<i64> = case["sorted_indices"]
            .as_array()
            .unwrap()
            .iter()
            .map(|v| v.as_i64().unwrap())
            .collect();

        let trials: Vec<FrozenTrial> = values
            .iter()
            .enumerate()
            .map(|(i, v)| make_trial(i as i64, v.clone()))
            .collect();
        let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
        let dirs: Vec<StudyDirection> = vec![StudyDirection::Minimize; values[0].len()];
        let cd = crowding_distance(&trial_refs, &dirs);

        // Check distances match
        for (j, (&got, &exp)) in cd.iter().zip(expected_dists.iter()).enumerate() {
            assert_close(got, exp, TOL, &format!("cd_sort[{ci}][{j}]"));
        }

        // Check sort order (descending by distance)
        let mut indices: Vec<usize> = (0..cd.len()).collect();
        indices.sort_by(|&a, &b| cd[b].partial_cmp(&cd[a]).unwrap_or(std::cmp::Ordering::Equal));
        let sorted_i64: Vec<i64> = indices.iter().map(|&i| i as i64).collect();
        assert_eq!(
            sorted_i64, expected_sorted,
            "cd_sort_order[{ci}] sort mismatch"
        );
    }
}

