#[test]
fn deep_cv_large_3obj_front0_cd() {
    let b = load();
    let sec = &b["large_3obj"];
    let values: Vec<Vec<f64>> = sec["values"]
        .as_array()
        .unwrap()
        .iter()
        .map(|row| row.as_array().unwrap().iter().map(|v| v.as_f64().unwrap()).collect())
        .collect();
    let expected_ranks = ji64_vec(&sec["ranks"]);
    let expected_cd = &sec["front0_cd"];

    let dirs = vec![
        StudyDirection::Minimize,
        StudyDirection::Minimize,
        StudyDirection::Minimize,
    ];
    let trials: Vec<FrozenTrial> = values
        .iter()
        .enumerate()
        .map(|(i, v)| make_trial(i as i64, v.clone()))
        .collect();

    // Extract front 0 trials
    let front0_indices: Vec<usize> = expected_ranks
        .iter()
        .enumerate()
        .filter(|&(_, &r)| r == 0)
        .map(|(i, _)| i)
        .collect();

    let front0_trials: Vec<&FrozenTrial> =
        front0_indices.iter().map(|&i| &trials[i]).collect();
    let cd = crowding_distance(&front0_trials, &dirs);

    for (j, &idx) in front0_indices.iter().enumerate() {
        let key = idx.to_string();
        let exp = jf64(&expected_cd[&key]);
        assert_close(
            cd[j],
            exp,
            TOL,
            &format!("large_3obj front0_cd[trial {idx}]"),
        );
    }
}

