//  6. Algorithmic properties — invariants that must ALWAYS hold
// ═══════════════════════════════════════════════════════════════════════════

/// Antisymmetry: if a dominates b, then b does NOT dominate a
#[test]
fn deep_cv_dominates_antisymmetry() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let test_pairs = vec![
        (vec![1.0, 2.0], vec![2.0, 3.0]),
        (vec![0.0, 0.0], vec![1.0, 1.0]),
        (vec![1.0, 1.0], vec![1.0, 2.0]),
    ];
    for (a, b) in test_pairs {
        if dominates(&a, &b, &dirs) {
            assert!(!dominates(&b, &a, &dirs), "antisymmetry violated: a={a:?} b={b:?}");
        }
    }
}

/// Irreflexivity: a does NOT dominate itself
#[test]
fn deep_cv_dominates_irreflexive() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Maximize];
    let vals = vec![
        vec![1.0, 2.0],
        vec![0.0, 0.0],
        vec![f64::INFINITY, f64::NEG_INFINITY],
    ];
    for v in vals {
        assert!(!dominates(&v, &v, &dirs), "irreflexivity violated: v={v:?}");
    }
}

/// Transitivity: if a dom b and b dom c, then a dom c
#[test]
fn deep_cv_dominates_transitivity() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let a = vec![1.0, 1.0];
    let b = vec![2.0, 2.0];
    let c = vec![3.0, 3.0];
    assert!(dominates(&a, &b, &dirs));
    assert!(dominates(&b, &c, &dirs));
    assert!(dominates(&a, &c, &dirs), "transitivity violated");
}

/// Front 0 is non-empty for non-empty input
#[test]
fn deep_cv_fns_front0_nonempty() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    for n in 1..=5 {
        let trials: Vec<FrozenTrial> = (0..n)
            .map(|i| make_trial(i as i64, vec![i as f64, (n - i) as f64]))
            .collect();
        let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
        let fronts = fast_non_dominated_sort(&trial_refs, &dirs);
        assert!(!fronts.is_empty(), "fronts empty for n={n}");
        assert!(!fronts[0].is_empty(), "front0 empty for n={n}");
    }
}

/// All trials are assigned exactly one rank
#[test]
fn deep_cv_fns_complete_partition() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let trials: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 4.0]),
        make_trial(1, vec![2.0, 3.0]),
        make_trial(2, vec![3.0, 2.0]),
        make_trial(3, vec![4.0, 4.0]),
        make_trial(4, vec![5.0, 5.0]),
    ];
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let fronts = fast_non_dominated_sort(&trial_refs, &dirs);

    let total: usize = fronts.iter().map(|f| f.len()).sum();
    assert_eq!(total, trials.len(), "not all trials assigned");

    // Each index appears exactly once
    let mut seen = vec![false; trials.len()];
    for front in &fronts {
        for &idx in front {
            assert!(!seen[idx], "index {idx} appears in multiple fronts");
            seen[idx] = true;
        }
    }
}

/// Within a front, no solution dominates another
#[test]
fn deep_cv_fns_no_intra_front_dominance() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let trials: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 6.0]),
        make_trial(1, vec![2.0, 5.0]),
        make_trial(2, vec![3.0, 4.0]),
        make_trial(3, vec![2.0, 6.0]),
        make_trial(4, vec![3.0, 5.0]),
        make_trial(5, vec![4.0, 4.0]),
        make_trial(6, vec![5.0, 6.0]),
        make_trial(7, vec![6.0, 5.0]),
        make_trial(8, vec![7.0, 7.0]),
    ];
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let fronts = fast_non_dominated_sort(&trial_refs, &dirs);

    for (r, front) in fronts.iter().enumerate() {
        for &i in front {
            for &j in front {
                if i == j {
                    continue;
                }
                let vi = trials[i].values.as_ref().unwrap();
                let vj = trials[j].values.as_ref().unwrap();
                assert!(
                    !dominates(vi, vj, &dirs),
                    "front {r}: trial {i} dominates trial {j}"
                );
            }
        }
    }
}

/// Crowding distance is non-negative
#[test]
fn deep_cv_cd_non_negative() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    let trials: Vec<FrozenTrial> = (0..10)
        .map(|i| make_trial(i, vec![i as f64 * 1.5, 10.0 - i as f64]))
        .collect();
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let cd = crowding_distance(&trial_refs, &dirs);
    for (i, &d) in cd.iter().enumerate() {
        assert!(d >= 0.0, "negative crowding distance at index {i}: {d}");
    }
}

/// With 2 trials, both get infinite crowding distance
#[test]
fn deep_cv_cd_two_trials_always_inf() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    for (a, b) in [(1.0, 2.0), (0.0, 100.0), (-1.0, 1.0)] {
        let trials = vec![
            make_trial(0, vec![a, b]),
            make_trial(1, vec![b, a]),
        ];
        let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
        let cd = crowding_distance(&trial_refs, &dirs);
        assert!(cd[0].is_infinite(), "2 trials: dist[0] should be inf, got {}", cd[0]);
        assert!(cd[1].is_infinite(), "2 trials: dist[1] should be inf, got {}", cd[1]);
    }
}
